import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.CMAFtOGK.js";const c=JSON.parse('{"title":"00 考试大纲与题型","description":"政治理论 · 00 考试大纲与题型","frontmatter":{"title":"00 考试大纲与题型","description":"政治理论 · 00 考试大纲与题型","category":"politics-note"},"headers":[],"relativePath":"posts/politics/notes/00-考试大纲与题型.md","filePath":"posts/politics/notes/00-考试大纲与题型.md","lastUpdated":1784753089000}'),r={name:"posts/politics/notes/00-考试大纲与题型.md"};function i(s,t,d,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="政治理论-·-考试大纲与题型" tabindex="-1">政治理论 · 考试大纲与题型 <a class="header-anchor" href="#政治理论-·-考试大纲与题型" aria-label="Permalink to &quot;政治理论 · 考试大纲与题型&quot;">​</a></h1><blockquote><p>🎯 <strong>一句话</strong>：广东普通专升本公共课《政治理论》· 满分 <strong>100</strong> · <strong>120 分钟</strong> 📅 考纲同步：2026 公开考试范围（以当年省考试院文件为准）</p></blockquote><hr><h2 id="一、试卷结构-常见版本" tabindex="-1">一、试卷结构（常见版本） <a class="header-anchor" href="#一、试卷结构-常见版本" aria-label="Permalink to &quot;一、试卷结构（常见版本）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">题型</th><th style="text-align:center;">题量</th><th style="text-align:center;">分值</th><th style="text-align:left;">备考要点</th></tr></thead><tbody><tr><td style="text-align:left;">单项选择题</td><td style="text-align:center;">20</td><td style="text-align:center;">20</td><td style="text-align:left;">概念、时间、人物、表述正误</td></tr><tr><td style="text-align:left;">多项选择题</td><td style="text-align:center;">10</td><td style="text-align:center;">20</td><td style="text-align:left;"><strong>最易失分</strong>，宁缺毋滥，抓关键词</td></tr><tr><td style="text-align:left;">辨析题</td><td style="text-align:center;">2</td><td style="text-align:center;">14</td><td style="text-align:left;">先判正误，再改错补全</td></tr><tr><td style="text-align:left;">问答题</td><td style="text-align:center;">3</td><td style="text-align:center;">21</td><td style="text-align:left;">分点 1.2.3.，专有名词写全</td></tr><tr><td style="text-align:left;">论述题</td><td style="text-align:center;">1</td><td style="text-align:center;">10</td><td style="text-align:left;">原理 + 展开 + 现实意义</td></tr><tr><td style="text-align:left;">材料分析题</td><td style="text-align:center;">1</td><td style="text-align:center;">15</td><td style="text-align:left;"><strong>观点 → 结合材料 → 结论</strong></td></tr><tr><td style="text-align:left;"><strong>合计</strong></td><td style="text-align:center;"></td><td style="text-align:center;"><strong>100</strong></td><td style="text-align:left;"></td></tr></tbody></table><blockquote><p>题型分值以<strong>当年考试大纲</strong>为准，跨年可能微调。</p></blockquote><hr><h2 id="二、考试范围-2026-公开表述摘要" tabindex="-1">二、考试范围（2026 公开表述摘要） <a class="header-anchor" href="#二、考试范围-2026-公开表述摘要" aria-label="Permalink to &quot;二、考试范围（2026 公开表述摘要）&quot;">​</a></h2><ol><li>马克思主义中国化时代化的历史进程与理论成果</li><li>毛泽东思想及其历史地位</li><li>新民主主义革命理论</li><li>社会主义改造理论</li><li>社会主义建设道路初步探索的理论成果</li><li>中国特色社会主义理论体系的形成发展</li><li>邓小平理论 · “三个代表”重要思想 · 科学发展观</li><li><strong>习近平新时代中国特色社会主义思想</strong>（形成与历史地位、中国式现代化、党的全面领导、以人民为中心、全面深化改革开放、高质量发展、教育科技人才、全过程人民民主、全面依法治国、文化强国、民生社会建设、生态文明、国家安全、国防军队、“一国两制”与祖国统一、大国外交与人类命运共同体、全面从严治党等）</li><li><strong>时事政治</strong>（考前一年国内外重大时事与重大路线方针政策）</li></ol><hr><h2 id="三、参考书目" tabindex="-1">三、参考书目 <a class="header-anchor" href="#三、参考书目" aria-label="Permalink to &quot;三、参考书目&quot;">​</a></h2><ol><li>《毛泽东思想和中国特色社会主义理论体系概论》（2023 年版），高等教育出版社</li><li>《习近平新时代中国特色社会主义思想概论》，高等教育出版社、人民出版社，2023 年 8 月</li></ol><hr><h2 id="四、本站笔记地图" tabindex="-1">四、本站笔记地图 <a class="header-anchor" href="#四、本站笔记地图" aria-label="Permalink to &quot;四、本站笔记地图&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">模块</th><th style="text-align:left;">笔记</th></tr></thead><tbody><tr><td style="text-align:left;">总纲</td><td style="text-align:left;">本页</td></tr><tr><td style="text-align:left;">毛中特主线</td><td style="text-align:left;">01-马克思主义中国化时代化 · 02-毛泽东思想 · 03-新民主主义革命 · 04-社会主义改造 · 05-建设道路初步探索</td></tr><tr><td style="text-align:left;">中国特色</td><td style="text-align:left;">06-中国特色社会主义理论体系 · 07-邓小平理论 · 08-三个代表与科学发展观</td></tr><tr><td style="text-align:left;">新时代</td><td style="text-align:left;">09-习思想形成与历史地位 · 10-中国式现代化 · 11-党的领导与以人民为中心 · 12-改革发展与五位一体 · 13-民主法治文化民生 · 14-生态安全国防统一外交 · 15-全面从严治党</td></tr><tr><td style="text-align:left;">得分技巧</td><td style="text-align:left;">16-时事政治备考 · 17-辨析论述材料题模板 · 18-必背金句与名词</td></tr></tbody></table><hr><h2 id="五、三轮刷法" tabindex="-1">五、三轮刷法 <a class="header-anchor" href="#五、三轮刷法" aria-label="Permalink to &quot;五、三轮刷法&quot;">​</a></h2><ol><li><strong>第一轮</strong>：按模块笔记过概念 + 闭卷默写金句</li><li><strong>第二轮</strong>：按年演练页（2018–2024）限时</li><li><strong>第三轮</strong>：材料题 / 论述题限时默写 + 对答案补表述</li></ol><p>返回：<a href="/zhuan-sheng-ben-notes/posts/politics/">政治</a> · <a href="/zhuan-sheng-ben-notes/posts/politics/">_索引</a></p>',19)])])}const y=e(r,[["render",i]]);export{c as __pageData,y as default};
